// avio_list_dir.c - استعراض محتويات مجلد عبر AVIO
#include <libavformat/avformat.h>
#include <stdio.h>

int main(int argc, char **argv) {
    const char *path = argc > 1 ? argv[1] : ".";
    AVIODirContext *dir = NULL;
    const char *entry_name;

    if (avio_open_dir(&dir, path, NULL) < 0) {
        fprintf(stderr, "فشل فتح المجلد: %s\n", path);
        return 1;
    }

    while ((entry_name = avio_read_dir(dir)) != NULL) {
        printf("ملف: %s\n", entry_name);
    }

    avio_close_dir(&dir);
    return 0;
}

